(function(root, ctx){
  if (!root) return;

  var initKey = 'mfFrenchProductSliderInit';
  if (root.dataset && root.dataset[initKey] === '1') return;
  if (root.dataset) root.dataset[initKey] = '1';

  var track = root.querySelector('.fr-slider-track');
  var slides = Array.prototype.slice.call(root.querySelectorAll('.fr-slide'));
  var prevBtn = root.querySelector('.fr-slider-prev');
  var nextBtn = root.querySelector('.fr-slider-next');
  var dotsWrap = root.querySelector('.fr-slider-dots');

  if (!track || !slides.length) return;

  var index = 0;
  var perView = 1;
  var maxIndex = 0;
  var timer = null;
  var touchStartX = null;
  var cleanupFns = [];

  function addCleanup(fn){
    cleanupFns.push(fn);
  }

  function getPerView(){
    var rect = root && root.getBoundingClientRect ? root.getBoundingClientRect() : null;
    var width = rect && rect.width ? rect.width : (window.innerWidth || 1200);
    if (width <= 540) return 1;
    if (width <= 780) return 2;
    if (width <= 1100) return 3;
    if (width <= 1500) return 4;
    return 5;
  }

  function getGap(){
    var styles = window.getComputedStyle(track);
    var gap = parseFloat(styles.gap || styles.columnGap || '0');
    return isNaN(gap) ? 0 : gap;
  }

  function getStepWidth(){
    if (!slides.length) return 0;
    var rect = slides[0].getBoundingClientRect();
    return rect.width + getGap();
  }

  function clamp(value){
    if (value < 0) return 0;
    if (value > maxIndex) return maxIndex;
    return value;
  }

  function updateButtons(){
    if (prevBtn) prevBtn.disabled = index <= 0;
    if (nextBtn) nextBtn.disabled = index >= maxIndex;
  }

  function updateDots(){
    if (!dotsWrap) return;
    var dots = dotsWrap.querySelectorAll('.fr-dot');
    for (var i = 0; i < dots.length; i++) {
      dots[i].classList.toggle('active', i === index);
      dots[i].setAttribute('aria-current', i === index ? 'true' : 'false');
    }
  }

  function render(){
    var step = getStepWidth();
    track.style.transform = 'translateX(-' + (index * step) + 'px)';
    updateButtons();
    updateDots();
  }

  function goTo(nextIndex){
    index = clamp(nextIndex);
    render();
  }

  function buildDots(){
    if (!dotsWrap) return;
    dotsWrap.innerHTML = '';
    for (var i = 0; i <= maxIndex; i++) {
      (function(dotIndex){
        var btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'fr-dot' + (dotIndex === index ? ' active' : '');
        btn.setAttribute('data-index', String(dotIndex));
        btn.setAttribute('aria-label', 'Go to slide ' + (dotIndex + 1));
        btn.addEventListener('click', function(){ goTo(dotIndex); });
        dotsWrap.appendChild(btn);
      })(i);
    }
  }

  function recalc(rebuildDots){
    perView = getPerView();
    maxIndex = Math.max(0, slides.length - perView);
    index = clamp(index);
    if (rebuildDots) buildDots();
    render();
  }

  function stopAutoplay(){
    if (timer) {
      window.clearInterval(timer);
      timer = null;
    }
  }

  function startAutoplay(){
    stopAutoplay();
    if (maxIndex <= 0) return;
    timer = window.setInterval(function(){
      goTo(index >= maxIndex ? 0 : index + 1);
    }, 5000);
  }

  if (prevBtn) {
    prevBtn.addEventListener('click', function(){ goTo(index - 1); });
  }

  if (nextBtn) {
    nextBtn.addEventListener('click', function(){ goTo(index + 1); });
  }

  track.addEventListener('touchstart', function(e){
    if (!e.touches || !e.touches.length) return;
    touchStartX = e.touches[0].clientX;
  }, { passive: true });

  track.addEventListener('touchend', function(e){
    if (touchStartX == null || !e.changedTouches || !e.changedTouches.length) return;
    var delta = e.changedTouches[0].clientX - touchStartX;
    if (Math.abs(delta) > 40) {
      goTo(delta > 0 ? index - 1 : index + 1);
    }
    touchStartX = null;
  }, { passive: true });

  var pauseTarget = root.querySelector('.fr-slider-container') || root;
  if (pauseTarget) {
    var onEnter = function(){ stopAutoplay(); };
    var onLeave = function(){ startAutoplay(); };
    pauseTarget.addEventListener('mouseenter', onEnter);
    pauseTarget.addEventListener('mouseleave', onLeave);
    addCleanup(function(){
      pauseTarget.removeEventListener('mouseenter', onEnter);
      pauseTarget.removeEventListener('mouseleave', onLeave);
    });
  }

  var onResize = function(){ recalc(true); };
  window.addEventListener('resize', onResize);
  addCleanup(function(){ window.removeEventListener('resize', onResize); });

  addCleanup(function(){ stopAutoplay(); });
  addCleanup(function(){
    if (root.dataset) delete root.dataset[initKey];
  });

  if (ctx && typeof ctx.registerCleanup === 'function') {
    ctx.registerCleanup(cleanupFns);
  }

  recalc(true);
  startAutoplay();
})(window.__mfCurrentScriptRoot, window.__mfScriptContext);

